import { DocumentNode, ApolloError, useMutation as useApolloMutation } from '@apollo/client';
import { useState } from 'react';

type UseMutationOptions<TData, TVariables> = {
  mutation: DocumentNode;
  optimisticResponse?: (variables: TVariables) => TData;
  onCompleted?: (data: TData) => void;
  onError?: (error: ApolloError) => void;
};

export function useMutation<TData, TVariables>(
  options: UseMutationOptions<TData, TVariables>
): [
  (variables: TVariables) => Promise<TData>,
  { loading: boolean; error?: ApolloError }
] {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<ApolloError | undefined>();

  const [executeMutation] = useApolloMutation(options.mutation, {
    optimisticResponse: options.optimisticResponse
      ? { __typename: 'Mutation', ...options.optimisticResponse }
      : undefined,
    onCompleted: (data) => {
      setLoading(false);
      setError(undefined);
      options.onCompleted?.(data);
    },
    onError: (apolloError) => {
      setLoading(false);
      setError(apolloError);
      options.onError?.(apolloError);
    },
  });

  const mutationFn = async (variables: TVariables): Promise<TData> => {
    setLoading(true);
    setError(undefined);

    try {
      const result = await executeMutation({ variables });
      return result.data;
    } catch (err) {
      const apolloError = err as ApolloError;
      setError(apolloError);
      throw apolloError;
    }
  };

  return [mutationFn, { loading, error }];
}

