type BatchLoadFn<K, V> = (keys: K[]) => Promise<V[]>;

interface DataLoaderOptions {
  cache?: boolean;
}

export class DataLoader<K, V> {
  private batchLoadFn: BatchLoadFn<K, V>;
  private cache: Map<K, Promise<V>>;
  private queue: K[] = [];
  private batchScheduled = false;
  private cacheEnabled: boolean;
  private pending: Map<K, { resolve: (v: V) => void; reject: (e: Error) => void }[]> = new Map();

  constructor(batchLoadFn: BatchLoadFn<K, V>, options?: DataLoaderOptions) {
    this.batchLoadFn = batchLoadFn;
    this.cache = new Map();
    this.cacheEnabled = options?.cache !== false;
  }

  load(key: K): Promise<V> {
    // Return cached promise if available
    if (this.cacheEnabled && this.cache.has(key)) {
      return this.cache.get(key)!;
    }

    // Create promise for this key
    const promise = new Promise<V>((resolve, reject) => {
      if (!this.pending.has(key)) {
        this.pending.set(key, []);
        this.queue.push(key);
      }
      this.pending.get(key)!.push({ resolve, reject });
    });

    // Cache the promise
    if (this.cacheEnabled) {
      this.cache.set(key, promise);
    }

    // Schedule batch processing
    if (!this.batchScheduled) {
      this.scheduleBatch();
    }

    return promise;
  }

  loadMany(keys: K[]): Promise<(V | Error)[]> {
    return Promise.all(
      keys.map((key) =>
        this.load(key)
          .then((value) => value)
          .catch((error) => error)
      )
    );
  }

  clear(key: K): this {
    this.cache.delete(key);
    return this;
  }

  clearAll(): this {
    this.cache.clear();
    return this;
  }

  private scheduleBatch(): void {
    this.batchScheduled = true;
    Promise.resolve().then(() => this.processBatch());
  }

  private processBatch(): void {
    const queue = this.queue;
    this.queue = [];
    this.batchScheduled = false;

    if (queue.length === 0) return;

    // Remove duplicates while preserving order
    const uniqueQueue = Array.from(new Map(queue.map((k) => [k, k])).values());

    this.batchLoadFn(uniqueQueue)
      .then((values) => {
        uniqueQueue.forEach((key, index) => {
          const value = values[index];
          const callbacks = this.pending.get(key) || [];
          callbacks.forEach((cb) => cb.resolve(value));
          this.pending.delete(key);
        });
      })
      .catch((error) => {
        uniqueQueue.forEach((key) => {
          const callbacks = this.pending.get(key) || [];
          callbacks.forEach((cb) => cb.reject(error));
          this.pending.delete(key);
        });
      });
  }
}

