interface PaginationArgs {
  first?: number;
  after?: string;
  last?: number;
  before?: string;
}

interface Edge<T> {
  cursor: string;
  node: T;
}

interface PageInfo {
  startCursor: string | null;
  endCursor: string | null;
  hasNextPage: boolean;
  hasPreviousPage: boolean;
}

interface Connection<T> {
  edges: Edge<T>[];
  pageInfo: PageInfo;
  totalCount: number;
}

function encodeCursor(value: string | number): string {
  return Buffer.from(String(value), 'utf-8').toString('base64');
}

function decodeCursor(cursor: string): string {
  return Buffer.from(cursor, 'base64').toString('utf-8');
}

export function paginate<T>(
  items: T[],
  args: PaginationArgs,
  getCursorValue: (item: T) => string | number
): Connection<T> {
  const { first, after, last, before } = args;
  const totalCount = items.length;

  // Validate arguments
  if (first !== undefined && first < 0) {
    throw new Error('first must be non-negative');
  }
  if (last !== undefined && last < 0) {
    throw new Error('last must be non-negative');
  }
  if (first !== undefined && last !== undefined) {
    throw new Error('Cannot specify both first and last');
  }

  // Find start index
  let startIndex = 0;
  if (after) {
    const afterValue = decodeCursor(after);
    startIndex = items.findIndex((item) => String(getCursorValue(item)) === afterValue) + 1;
    if (startIndex === 0) startIndex = 0; // Cursor not found, start from beginning
  }

  // Find end index
  let endIndex = items.length;
  if (before) {
    const beforeValue = decodeCursor(before);
    endIndex = items.findIndex((item) => String(getCursorValue(item)) === beforeValue);
    if (endIndex === -1) endIndex = items.length; // Cursor not found
  }

  // Apply first/last limits
  if (first !== undefined) {
    endIndex = Math.min(startIndex + first, endIndex);
  } else if (last !== undefined) {
    startIndex = Math.max(endIndex - last, startIndex);
  }

  // Extract slice
  const slicedItems = items.slice(startIndex, endIndex);

  // Create edges
  const edges: Edge<T>[] = slicedItems.map((item) => ({
    cursor: encodeCursor(getCursorValue(item)),
    node: item,
  }));

  // Determine page info
  const pageInfo: PageInfo = {
    startCursor: edges.length > 0 ? edges[0].cursor : null,
    endCursor: edges.length > 0 ? edges[edges.length - 1].cursor : null,
    hasNextPage: endIndex < items.length,
    hasPreviousPage: startIndex > 0,
  };

  return {
    edges,
    pageInfo,
    totalCount,
  };
}

