import DataLoader from 'dataloader';
import { gql, useMutation, useQuery, ApolloClient, InMemoryCache } from '@apollo/client';
import { base64, unbase64 } from './utils';

// Simulated database
const postsDB = [
  { id: 'post-1', content: 'Hello', authorId: 'user-1', likes: 5, createdAt: new Date('2024-01-01') },
  { id: 'post-2', content: 'World', authorId: 'user-2', likes: 10, createdAt: new Date('2024-01-02') },
];

const usersDB = [
  { id: 'user-1', name: 'Alice', email: 'alice@example.com' },
  { id: 'user-2', name: 'Bob', email: 'bob@example.com' },
];

// DataLoader for batching user queries
const userLoader = new DataLoader(async (userIds: string[]) => {
  const uniqueIds = [...new Set(userIds)];
  const users = usersDB.filter(u => uniqueIds.includes(u.id));
  return userIds.map(id => users.find(u => u.id === id) || null);
});

// GraphQL Queries and Mutations
const GET_POSTS = gql`
  query GetPosts($after: String, $first: Int) {
    posts(after: $after, first: $first) {
      edges {
        node {
          id
          content
          author {
            id
            name
          }
          likes
          likedByCurrentUser
          createdAt
        }
        cursor
      }
      pageInfo {
        hasNextPage
        endCursor
      }
    }
  }
`;

const LIKE_POST = gql`
  mutation LikePost($postId: ID!) {
    likePost(postId: $postId) {
      id
      likes
      likedByCurrentUser
    }
  }
`;

// Cursor encoding/decoding helpers
const encodeCursor = (id: string): string => base64(`post:${id}`);
const decodeCursor = (cursor: string): string => {
  const decoded = unbase64(cursor);
  return decoded.replace('post:', '');
};

// Resolver for posts query
export const postsResolver = async (parent, args, context) => {
  const { after, first = 10 } = args;

  let posts = [...postsDB].sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());

  // Apply cursor-based pagination
  let startIndex = 0;
  if (after) {
    const afterId = decodeCursor(after);
    startIndex = posts.findIndex(p => p.id === afterId) + 1;
  }

  const paginatedPosts = posts.slice(startIndex, startIndex + first + 1);
  const hasNextPage = paginatedPosts.length > first;
  const edges = paginatedPosts.slice(0, first).map(post => ({
    node: post,
    cursor: encodeCursor(post.id)
  }));

  return {
    edges,
    pageInfo: {
      hasNextPage,
      endCursor: edges.length > 0 ? edges[edges.length - 1].cursor : null
    }
  };
};

// Author resolver using DataLoader
export const authorResolver = (post) => {
  return userLoader.load(post.authorId);
};

// Apollo Client setup
const cache = new InMemoryCache({
  typePolicies: {
    PostConnection: {
      merge(existing = { edges: [] }, incoming) {
        return incoming;
      }
    },
    Query: {
      fields: {
        posts: {
          merge(existing, incoming, { args }) {
            if (!args?.after) {
              return incoming;
            }
            return existing ? { ...existing, ...incoming } : incoming;
          }
        }
      }
    }
  }
});

const client = new ApolloClient({
  cache,
  uri: 'http://localhost:4000/graphql'
});

// useLikeMutation hook
export const useLikeMutation = () => {
  const [likeMutation] = useMutation(LIKE_POST, {
    optimisticResponse: (variables) => ({
      likePost: {
        __typename: 'Post',
        id: variables.postId,
        likes: 0,
        likedByCurrentUser: true
      }
    }),
    update: (cache, { data: { likePost } }) => {
      const existing = cache.readQuery({
        query: GET_POSTS,
        variables: { after: null, first: 10 }
      });

      if (existing) {
        const updatedEdges = existing.posts.edges.map(edge => {
          if (edge.node.id === likePost.id) {
            return {
              ...edge,
              node: {
                ...edge.node,
                likes: likePost.likes,
                likedByCurrentUser: likePost.likedByCurrentUser
              }
            };
          }
          return edge;
        });

        cache.writeQuery({
          query: GET_POSTS,
          variables: { after: null, first: 10 },
          data: {
            posts: {
              ...existing.posts,
              edges: updatedEdges
            }
          }
        });
      }
    }
  });

  return (postId: string) => {
    return likeMutation({ variables: { postId } });
  };
};

