interface SubscriptionConfig {
  onMessage: (data: unknown) => void;
  onError: (error: Error) => void;
  onComplete: () => void;
  maxRetries: number;
  retryDelay: number;
}

class GraphQLSubscriptionManager {
  private activeSubscriptions = new Map<string, Set<SubscriptionConfig>>();
  private webSockets = new Map<string, WebSocket>();
  private retryAttempts = new Map<string, number>();
  private timers = new Map<string, NodeJS.Timeout>();
  private messageQueues = new Map<string, unknown[]>();
  private isProcessing = new Map<string, boolean>();

  subscribe(topic: string, config: SubscriptionConfig): { unsubscribe: () => void } {
    if (!this.activeSubscriptions.has(topic)) {
      this.activeSubscriptions.set(topic, new Set());
      this.messageQueues.set(topic, []);
      this.connectWebSocket(topic, config, 0);
    }

    this.activeSubscriptions.get(topic)!.add(config);

    return {
      unsubscribe: () => {
        const subscribers = this.activeSubscriptions.get(topic);
        if (subscribers) {
          subscribers.delete(config);
          if (subscribers.size === 0) {
            this.cleanup(topic);
          }
        }
      }
    };
  }

  private connectWebSocket(topic: string, config: SubscriptionConfig, attempt: number = 0): void {
    if (attempt > config.maxRetries) {
      const error = new Error(`Failed to connect after ${config.maxRetries} attempts`);
      config.onError(error);
      return;
    }

    try {
      const ws = new WebSocket(`ws://localhost:8000/graphql?topic=${topic}`);

      ws.onopen = () => {
        this.webSockets.set(topic, ws);
        this.retryAttempts.set(topic, 0);
        this.processMessageQueue(topic);
      };

      ws.onmessage = (event) => {
        const message = JSON.parse(event.data);
        const queue = this.messageQueues.get(topic) || [];
        queue.push(message);
        this.messageQueues.set(topic, queue);
        this.processMessageQueue(topic);
      };

      ws.onerror = (error) => {
        const subscribers = this.activeSubscriptions.get(topic) || new Set();
        for (const subscriber of subscribers) {
          subscriber.onError(new Error(`WebSocket error: ${error}`));
        }
      };

      ws.onclose = () => {
        this.webSockets.delete(topic);
        const newAttempt = (this.retryAttempts.get(topic) || 0) + 1;
        this.retryAttempts.set(topic, newAttempt);

        if (newAttempt <= config.maxRetries) {
          const delay = this.calculateBackoff(newAttempt, config.retryDelay);
          const timer = setTimeout(() => {
            this.connectWebSocket(topic, config, newAttempt);
          }, delay);
          this.timers.set(`${topic}-retry-${newAttempt}`, timer);
        }
      };
    } catch (error) {
      const delay = this.calculateBackoff(attempt, config.retryDelay);
      const timer = setTimeout(() => {
        this.connectWebSocket(topic, config, attempt + 1);
      }, delay);
      this.timers.set(`${topic}-retry-${attempt}`, timer);
    }
  }

  private processMessageQueue(topic: string): void {
    if (this.isProcessing.get(topic)) return;

    this.isProcessing.set(topic, true);
    const queue = this.messageQueues.get(topic) || [];
    const subscribers = this.activeSubscriptions.get(topic) || new Set();

    while (queue.length > 0 && subscribers.size > 0) {
      const message = queue.shift();
      for (const subscriber of subscribers) {
        try {
          subscriber.onMessage(message);
        } catch (error) {
          subscriber.onError(error instanceof Error ? error : new Error(String(error)));
        }
      }
    }

    this.isProcessing.set(topic, false);
  }

  private calculateBackoff(attempt: number, baseDelay: number): number {
    return Math.min(baseDelay * Math.pow(2, attempt - 1), 30000);
  }

  private cleanup(topic: string): void {
    const ws = this.webSockets.get(topic);
    if (ws) {
      ws.close();
      this.webSockets.delete(topic);
    }

    this.activeSubscriptions.delete(topic);
    this.messageQueues.delete(topic);
    this.retryAttempts.delete(topic);
    this.isProcessing.delete(topic);

    const timers = Array.from(this.timers.keys()).filter(key => key.startsWith(topic));
    for (const timerKey of timers) {
      clearTimeout(this.timers.get(timerKey)!);
      this.timers.delete(timerKey);
    }
  }
}

