solution:
interface ErrorDetail {
  message: string;
  code: string;
  path: (string | number)[];
  details?: Record<string, unknown>;
}

interface PartialResponse<T> {
  data: Partial<T> | null;
  errors: ErrorDetail[];
}

interface GraphQLField {
  name: string;
  resolve: (parent: unknown, args: Record<string, unknown>) => Promise<unknown> | unknown;
  type: string;
  isNullable?: boolean;
}

class GraphQLErrorHandler {
  private fields: Map<string, GraphQLField> = new Map();
  private errors: ErrorDetail[] = [];
  private resolvedData: Record<string, unknown> = {};

  registerField(field: GraphQLField): void {
    this.fields.set(field.name, field);
  }

  async executeQuery<T>(
    rootValue: unknown,
    fields: Record<string, GraphQLField>,
    variables?: Record<string, unknown>
  ): Promise<PartialResponse<T>> {
    this.errors = [];
    this.resolvedData = {};

    for (const [fieldName, field] of Object.entries(fields)) {
      const result = await this.resolveField(field, rootValue, variables || {}, [fieldName]);
      this.resolvedData[fieldName] = result.value;
      this.errors.push(...result.errors);
    }

    const hasData = Object.values(this.resolvedData).some((v) => v !== null);

    return {
      data: (hasData ? this.resolvedData : null) as Partial<T>,
      errors: this.errors
    };
  }

  formatError(error: unknown, path: (string | number)[]): ErrorDetail {
    if (error instanceof GraphQLFieldError) {
      return {
        message: error.message,
        code: error.code,
        path,
        details: error.details
      };
    }

    if (error instanceof TypeError) {
      return {
        message: error.message,
        code: 'TYPE_ERROR',
        path,
        details: { stack: error.stack }
      };
    }

    if (error instanceof Error) {
      return {
        message: error.message,
        code: 'INTERNAL_ERROR',
        path,
        details: { stack: error.stack }
      };
    }

    return {
      message: String(error),
      code: 'UNKNOWN_ERROR',
      path
    };
  }

  private async resolveField(
    field: GraphQLField,
    parent: unknown,
    args: Record<string, unknown>,
    path: (string | number)[]
  ): Promise<{ value: unknown; errors: ErrorDetail[] }> {
    const fieldErrors: ErrorDetail[] = [];

    try {
      const value = await Promise.resolve(field.resolve(parent, args));

      if (Array.isArray(value)) {
        return this.resolveListField(value, field, path);
      }

      if (value !== null && typeof value === 'object') {
        return this.resolveObjectField(value, field, path);
      }

      return { value, errors: [] };
    } catch (error) {
      const errorDetail = this.formatError(error, path);
      fieldErrors.push(errorDetail);

      return {
        value: field.isNullable ? null : undefined,
        errors: fieldErrors
      };
    }
  }

  private async resolveListField(
    list: unknown[],
    field: GraphQLField,
    path: (string | number)[]
  ): Promise<{ value: unknown; errors: ErrorDetail[] }> {
    const errors: ErrorDetail[] = [];
    const resolvedItems: unknown[] = [];

    for (let i = 0; i < list.length; i++) {
      const itemPath = [...path, i];
      try {
        const item = list[i];
        if (item !== null && typeof item === 'object') {
          const result = await this.resolveNestedObject(item, field, itemPath);
          resolvedItems.push(result.value);
          errors.push(...result.errors);
        } else {
          resolvedItems.push(item);
        }
      } catch (error) {
        const errorDetail = this.formatError(error, itemPath);
        errors.push(errorDetail);
        resolvedItems.push(null);
      }
    }

    return {
      value: resolvedItems.length > 0 ? resolvedItems : null,
      errors
    };
  }

  private async resolveObjectField(
    obj: Record<string, unknown>,
    field: GraphQLField,
    path: (string | number)[]
  ): Promise<{ value: unknown; errors: ErrorDetail[] }> {
    const errors: ErrorDetail[] = [];

    try {
      const result = await this.resolveNestedObject(obj, field, path);
      return result;
    } catch (error) {
      const errorDetail = this.formatError(error, path);
      return {
        value: field.isNullable ? null : undefined,
        errors: [errorDetail]
      };
    }
  }

  private async resolveNestedObject(
    obj: Record<string, unknown>,
    parentField: GraphQLField,
    path: (string | number)[]
  ): Promise<{ value: Record<string, unknown>; errors: ErrorDetail[] }> {
    const errors: ErrorDetail[] = [];
    const resolvedObj: Record<string, unknown> = {};

    for (const [key, value] of Object.entries(obj)) {
      const fieldPath = [...path, key];
      try {
        if (Array.isArray(value)) {
          const result = await this.resolveListFieldForKey(value, fieldPath);
          resolvedObj[key] = result.value;
          errors.push(...result.errors);
        } else if (value !== null && typeof value === 'object') {
          const result = await this.resolveNestedObject(
            value as Record<string, unknown>,
            parentField,
            fieldPath
          );
          resolvedObj[key] = result.value;
          errors.push(...result.errors);
        } else {
          resolvedObj[key] = value;
        }
      } catch (error) {
        const errorDetail = this.formatError(error, fieldPath);
        errors.push(errorDetail);
        resolvedObj[key] = null;
      }
    }

    return { value: resolvedObj, errors };
  }

  private async resolveListFieldForKey(
    list: unknown[],
    path: (string | number)[]
  ): Promise<{ value: unknown; errors: ErrorDetail[] }> {
    const errors: ErrorDetail[] = [];
    const resolvedItems: unknown[] = [];

    for (let i = 0; i < list.length; i++) {
      const itemPath = [...path, i];
      try {
        const item = list[i];
        if (item !== null && typeof item === 'object' && !Array.isArray(item)) {
          const result = await this.resolveNestedObject(
            item as Record<string, unknown>,
            { name: '', resolve: () => {}, type: '' },
            itemPath
          );
          resolvedItems.push(result.value);
          errors.push(...result.errors);
        } else {
          resolvedItems.push(item);
        }
      } catch (error) {
        const errorDetail = this.formatError(error, itemPath);
        errors.push(errorDetail);
        resolvedItems.push(null);
      }
    }

    return { value: resolvedItems, errors };
  }
}

class GraphQLFieldError extends Error {
  constructor(
    message: string,
    public code: string,
    public details?: Record<string, unknown>
  ) {
    super(message);
    this.name = 'GraphQLFieldError';
  }
}

export { GraphQLErrorHandler, ErrorDetail, PartialResponse, GraphQLFieldError };
